package com.samudhra.certificates.repository; import com.samudhra.certificates.entity.Certificate; import org.springframework.data.jpa.repository.JpaRepository; import java.util.*; public interface CertificateRepository extends JpaRepository<Certificate,String>{ Optional<Certificate> findByCertificateNumber(String value); long countByOrganizationId(String id); List<Certificate> findByTemplateId(String templateId); @org.springframework.data.jpa.repository.Query("SELECT c FROM Certificate c WHERE c.certificateNumber = :query OR LOWER(c.student.name) LIKE LOWER(CONCAT('%', :query, '%'))") List<Certificate> findByCertificateNumberOrStudentName(@org.springframework.data.repository.query.Param("query") String query); }
